import MovieItem from "./MovieItem";

function MovieList({ movies, onDelete, onUpdate, onSelect }) {
    return (
        <div className="movie-grid">
            {movies.map((movie) => (
                <div
                    key={movie.id}
                    className="movie-card"
                    onClick={() => onSelect(movie)} // ✅ added
                >
                    <img src={movie.poster} alt={movie.title} />
                    <h3>{movie.title}</h3>
                </div>
            ))}
        </div>
    );
}

export default MovieList;
